const fetch = require('node-fetch');
const { Headers } = fetch; 
const { URLSearchParams } = require('url');
const qs = require('querystring');
const crypto = require('crypto');
const FormData = require('form-data');
const keys = $('FakeGetAccessToken').first().json;
const { ACCESS_TOKEN, PAGE_ID } = keys;


async function uploadMedia(i, fN, mT) {
  let url = `https://graph.facebook.com/v21.0/${PAGE_ID}/photos`;
  let method = 'POST';
  let buffer = await this.helpers.getBinaryDataBuffer(i, 'data')
  let formData = new FormData();
  formData.append('source', buffer, { filename: fN, contentType: mT });

  formData.append('published', 'false')

  let response = await fetch(url, {
    method: method,
    headers: {
      ...formData.getHeaders(),
      'Authorization': `OAuth ${ACCESS_TOKEN}`,
    },
    body: formData,
  });
  console.log(response)
  if (!response.ok) {
    console.error('Failed to upload media:', await response.text());
    return null;
  }
  const data = await response.json();
  console.log("Meta media upload result: ", data)
  return data.id;
}

async function postTweet(text, mediaIds) {
  let url = `https://graph.facebook.com/${PAGE_ID}/feed`;
  let method = 'POST';

  const myHeaders = new Headers();
  myHeaders.append("Content-Type", "application/x-www-form-urlencoded");
  const urlencoded = new URLSearchParams();
  urlencoded.append("message", text);
  for(let i = 0; i < mediaIds.length; i++ ){
    let key = "attached_media[" + i.toString() + "]"
    let value = "{media_fbid:" + mediaIds[i] + "}"
    console.log(key)
    console.log(value)
    urlencoded.append(key,value);
  }
  urlencoded.append("access_token", ACCESS_TOKEN);
  console.log('z: ',urlencoded)
  const requestOptions = {
    method: "POST",
    headers: myHeaders,
    body: urlencoded,
  };

  const response = await fetch(url, requestOptions);
  console.log('post tweet: ',response)
  if (!response.ok) {
    return null;
  }
  let res = await response.json()
  console.log('Tweet posted successfully:', res);
  return res;
}

async function handle() {
  let inputs = $input.all()
  let mediaIds = [];
  for (let i = 0; i < inputs.length; i ++) {
    let fileName = inputs[i]["binary"]["data"]["fileName"];
    let mimeType = inputs[i]["binary"]["data"]["mimeType"];
    let mediaId = await uploadMedia(i, fileName, mimeType);
    mediaIds.push(mediaId);
  }
  if (mediaIds.length) {
    const postTweetResult = await postTweet('Hi', mediaIds );
    return {
      tweet: postTweetResult,
      media: mediaIds
    };
  }
  return null;

}

const res = await handle();
if (res == null ){
  return {
    distributed: false
  }
} else {
  return {
    distributed: true,
    data: res
  }
}

const distributedMedias = $('GetMediaToDeliver').all().map(x => x["json"]);
const distributedFBaccount = $('LinkAndGroupTypeToGetMedia').first().json.Link
const input = $input.first()["json"];
const tweet = input["data"]["tweet"]["id"]
const part = tweet.split('_')
const tweetLink = `https://www.facebook.com/${part[0]}/posts/${part[1]}/`;

const values = distributedMedias.map(item => {
  const { Id } = item;
  return `(${Id}, '${distributedFBaccount}', '${tweetLink}' )`;
}).join(',\n');
const insertSQL = `
BEGIN TRANSACTION;

BEGIN TRY

  INSERT INTO XinhDistributionLog 
    (SourceId, DistributionTarget, DistributionLink) 
  VALUES ${values};

COMMIT TRANSACTION;
END TRY
BEGIN CATCH
    ROLLBACK TRANSACTION;
END CATCH;
`
return {
  query: insertSQL.replace(/\s+/g, ' ').trim()
}
